// ── ICS / iCal parser ────────────────────────────────────────────────────────
function parseICS(text) {
  const events = [];
  const blocks = text.split("BEGIN:VEVENT");
  for (let i = 1; i < blocks.length; i++) {
    const block = blocks[i];
    const get = (key) => {
      const m = block.match(new RegExp(`${key}[^:]*:([^\r\n]+)`));
      return m ? m[1].replace(/\\n/g, "\n").replace(/\\,/g, ",").trim() : "";
    };
    const summary = get("SUMMARY");
    if (!summary) continue;
    const dtstart = get("DTSTART");
    const dtend = get("DTEND");
    const uid = get("UID") || Math.random().toString(36).slice(2, 9);
    const parseICSDate = (d) => {
      if (!d) return null;
      const isUTC = d.endsWith("Z");
      const clean = d.replace(/[TZ]/g, "");
      const yr = parseInt(clean.slice(0, 4)) || new Date().getFullYear();
      const mo = Math.max(0, (parseInt(clean.slice(4, 6)) || 1) - 1);
      const dy = parseInt(clean.slice(6, 8)) || 1;
      const hr = parseInt(clean.slice(8, 10) || "0") || 0;
      const mn = parseInt(clean.slice(10, 12) || "0") || 0;
      return isUTC ? new Date(Date.UTC(yr, mo, dy, hr, mn)) : new Date(yr, mo, dy, hr, mn);
    };
    let start;
    try {
      start = parseICSDate(dtstart);
    } catch {
      continue;
    }
    if (!start) continue;
    let end;
    try {
      end = parseICSDate(dtend);
    } catch {
      end = null;
    }
    const fmtTime = (d) => {
      if (!d || isNaN(d.getTime())) return "";
      let h = d.getHours(), m = d.getMinutes();
      const ap = h >= 12 ? "PM" : "AM";
      h = h % 12 || 12;
      return `${h}:${String(m).padStart(2, "0")} ${ap}`;
    };
    events.push({ id: uid, title: summary, startTime: fmtTime(start), endTime: fmtTime(end),
      description: get("DESCRIPTION"), location: get("LOCATION"), importedFromIcs: true, _startDate: start });
  }
  return events;
}

// Auto-inject user's Anthropic API key OR Ollama config on all /api/chat calls
(function patchFetch() {
  const _orig = window.fetch.bind(window);
  window.fetch = function(url, opts) {
    if (typeof url === "string" && url === "/api/chat") {
      const userKey = localStorage.getItem("up_anthropic_key") || "";
      const ollamaUrl = localStorage.getItem("up_ollama_url") || "http://localhost:11434";
      const ollamaModel = localStorage.getItem("up_ollama_model") || "";
      // Only use Ollama when explicitly enabled — server handles Gemini fallback
      const useOllama = localStorage.getItem("up_use_ollama") === "true";
      const extra = {};
      if (userKey) extra["x-user-api-key"] = userKey;
      if (useOllama) extra["x-use-ollama"] = "true";
      if (ollamaUrl) extra["x-ollama-url"] = ollamaUrl;
      if (ollamaModel) extra["x-ollama-model"] = ollamaModel;
      if (Object.keys(extra).length) {
        opts = { ...opts, headers: { ...(opts?.headers || {}), ...extra } };
      }
    }
    return _orig(url, opts);
  };
}());

